#[Grantable(
    resource_type: 'invoice',
    display_label: 'Invoice',
    preflight_validator: InvoiceGrantPreflight::class,
    permission_prefix: 'invoice',
    target_picker_screen_ref: 'finance.pickers.invoice'
)]
final class Invoice extends Model
{
    use HasResourceGrants;
    use IsGrantable;
}

#[AsGrantListener(events: ['GrantIssued', 'GrantRevoked'], queue: 'notifications')]
final class SyncInvoiceAclCache
{
    public function handle(GrantIssued|GrantRevoked $event): void
    {
        InvoiceAclCache::forget($event->grant->resource_id);
    }
}
